<template>
  <div class="slider">
    <nav class="route">
      <a
        class="route_item"
        v-for="(item,index) of routeData"
        :key="index"
        :href="item.href"
      >{{ item.title }}</a>
    </nav>
    <div 
      class="swipe"
      @mouseover="stop"
      @mouseout="start"
    >
      <div 
        v-for="(img,index) of mainImageData"
        :key="index"
        class="swipe_item"
      >
        <transition 
          :name="slideDerection.slide"
        >
          <img 
            :src="img"
            v-show="index === slideDerection.picIndex"
            class="img"
          >
        </transition>
      </div>
      <span 
        class="prev point"
        @click="prev"
      >&lt;</span>
      <span
        class="next point"
        @click="next"
      >&gt;</span>
      <div class="swipe_derection">
        <span 
          class="swipe_item_point"
          :class="{'active': slideDerection.picIndex === i}"
          v-for="(item,i) of mainImageData"
          :key="i"
        />
      </div>
    </div>
    <a 
      class="right_img_log"
      :href="rightimgData.href"
    >
      <img :src="rightimgData.imgSrc">
    </a>
  </div>
</template>
<script>
export default {
    data (){
        return {
           
            slideDerection:{
                // 展示第几张图片,默认为第一张
                picIndex:0,
                slide:"slide_left"

            },
            routeData:[
                {
                    title:"首页",
                    href:"",
                },
                {
                    title:"团购",
                    href:"",
                },
                {
                    title:"商户",
                    href:"",
                }
            ],
            mainImageData:[
                require("../server/main1.jpg"),
                require("../server/main2.jpg"),
            ],
            rightimgData: {
                imgSrc:require("../server/right.jpg"),
                href:"",
            }


        };

    },
    mounted (){
        this.start();
        // 使定时器不在后台运行
        this.$once("hook:beforeDestroy",() => {
            clearInterval(this.timer);

        });

    },
    methods:{
        // 下一张图片
        next(){
            this.slideDerection.slide =  "slide_left";
            this.slideDerection.picIndex --;
            if(this.slideDerection.picIndex === -1){
                this.slideDerection.picIndex = this. mainImageData.length - 1;
            }

        },
        // 上一张图片
        prev (){
            this.slideDerection.slide = "slide_right";
            this.slideDerection.picIndex ++; 
            if(this.slideDerection.picIndex === this. mainImageData.length){
                this.slideDerection.picIndex = 0;
            }
        },
        // 停止图片动画
        stop(){
            if(this.timer){
                clearInterval(this.timer);
            }

        },
        // 开始图片动画
        start (){
            this.timer = setInterval(() => {
                this.next();
            }, 5000);

        },
    }
    
};
</script>
<style lang="scss" scoped>
.slider{
    width:974px;
    position: absolute;;
    left:226px;
    top:0;
    .route{
        height:40px;
        background-color:rgb(49,49,49);
        .route_item{
            height:100%;
            width:80px;
            text-align:center;
            display:inline-block;
            font-size:21px;
            line-height:40px;
            font-weight:500;
            padding:0 10px;
            color:white;
            &:hover{
                color:rgb(170,170,170);
            }
            &:first-child{
                background-color:black;
            }
        }
    }
    .swipe{
        font-size:0;
        position:relative;
        width:720px;
        height:245px;
        overflow:hidden;
        &:hover{
            .point{
                display:block;
            }
        }
        .swipe_item{
            width:100%;
            height:100%;
            overflow:hidden;
            position:absolute;
            .img{
                width:100%;
                height:100%;
            }
            .slide_left-leave-to,.slide_right-enter{
                transform:translateX(-100%);
            }
            .slide_left-enter,.slide_right-leave-to{
                transform:translateX(100%);

            }
            .slide_left-enter-active,.slide_left-leave-active, .slide_right-enter-active,.slide_right-leave-active{
                transition:all 0.5s ease-in-out;

            }
        }
        .point{
            width:35px;
            height:45px;
            display:inline-block;
            position: absolute;
            top:50%;
            z-index:9999;
            display:none;
            opacity:0.5;
            cursor: pointer;
            font-size:40px;
            font-weight: 500;
            line-height:45px;
            text-align:center;
            color:rgb(160,160,160);
            transform: translateY(-50%);
        }
        .prev{
            left:0;
            background:rgb(27,27,27);
        }
        .next{
            right:0;
            background:rgb(27,27,27);
        }
        .swipe_derection{
            position:absolute;
            bottom:10px;
            left:50%;
            transform: translateX(-50%);
            .swipe_item_point{
                width:15px;
                height:15px;
                display:inline-block;
                border-radius:50%;
                background-color:rgb(172,106,0);
                cursor: pointer;
                margin-left:15px;
                &:first-child{
                    margin:0;
                }
            }
            .active{
                background-color:rgb(243,152,0);
            }
        }
    }
    .right_img_log{
        position:absolute;
        top:40px;
        height:245px;
        width:252px;
        right:0;
        img{
            width:100%;
            height:100%;
        }
    }
}

</style>


