<template>
  <div class="shop">
    shop
  </div>
</template>
<script>
export default {
    beforeRouteEnter (to, from, next) {
        next(vm => {
            document.documentElement.scrollTop = vm.$store.state.scrollTop;
        });
    },
    beforeRouteLeave(to,from,next){
        let scrollTop = document.documentElement.scrollTop;
        this.setScrollTop(scrollTop);

        next();

    },
    methods:{
        // 设置商品详情页的scrolltop
        setScrollTop (pos){
            this.$store.commit("setScrollTop",pos);

        }
    }
    
};
</script>
<style lang="scss" scoped>
.shop{
    height:600px;
}

</style>