<template>
  <header class="header">
    <div class="header_inner">
      <div class="area">
        <div class="detail_area">
          <span>{{ currentCity }}</span>
        </div>
        <div class="border" />
        <div 
          class="switch_city"
          @mouseover="showStatus(true)"
          @mouseout="showStatus(false)"
        >
          <span>切换城市</span>
          <span class="switch_icon" />
          <div 
            class="hot_city"
            v-show="isHotCityShow"
          >
            <div class="hot_city_title">
              热门城市
            </div>
            <span 
              class="city_item"
              @click="selectCity"
              v-for="(item,index) of hotCities"
              :key="index"
              :data-city="item.city"
              :data-id="item.id"
            >{{ item.city }}</span>
          </div>
        </div>
      </div>
      <div class="shop">
        <span 
          class="fa-shopping-cart"
          @click="toShopList"
        />
        <span class="order_num">{{ orderNum }}</span>
      </div>
      <div 
        class="log_reg"
        v-if="user.user_name"
      >
        <div class="user_img">
          <img :src="user.user_img">
        </div>
        <div class="logined">
          你好,{{ user.user_name }}
        </div>
        <div 
          class="quit"
          @click="quit"
        >
          退出
        </div>
      </div>
      <div 
        class="log_reg"
        v-else
      >
        <a 
          class="login"
          @click="login"
        >登陆</a>
        <div class="border" />
        <a 
          class="register"
          @click="register"
        >注册</a>
      </div>
    </div>
  </header>
</template>
<script>
import api from "../api/components/api.js";
export default {
    data (){
        return {
            // 热门城市是否显示
            isHotCityShow:false,
            // 当前热门城市
            currentCity:"北京",
            hotCities:[],

        };
    }, 
    props:{
        // 用户信息
        user:{
            type:Object,
            default: function(){
                return {};
            }
        },
        // 登陆用户订单数
        orders:{
            type:Number,
            default:0
        }

    },
    computed:{
        orderNum:function (){
            return this.orders === 0 ?  " " : this.orders;
        }

    },
    created (){
        this.getHotCities();

    },
    methods:{
        /**
         * 热门城市显示或隐藏
         */
        showStatus (status){
            this.isHotCityShow = status;

        },
        /**
         * 选择热门城市
         */
        selectCity(event){
            let currentCity = event.target.dataset.city;
            this.currentCity = currentCity;


        },
        login (){
            const currentRoute = this.$router.fullPath;
            this.$router.push({
                path:"/login",
                query:{
                    redirect:currentRoute
                }
            });
        },
        register (){
            this.$router.push({
                path:"/register"
            });
        },
        //  退出登陆
        quit (){
            this.$emit("clearUser");
            this.$store.commit("setToken", null);
            localStorage.removeItem("token");
        },
        // 查看用户订单
        toShopList (){
            this.$router.push({
                path:"/pay"
            });
        },
        // 获取热门城市列表
        getHotCities (){
            this.axios.get(api.hotCities).then(response => {
                if(response.code === 200){
                    this.hotCities = response.data;
                }
                return;

            }).catch(error => {
                console.log(error);
            });

        }
    }
    
};
</script>
<style lang="scss" scoped>
.header{
    height:36px;
    background-color:whitesmoke;
    border-bottom:1px solid rgba(125,125,125,0.3);
    .header_inner{
        width:1200px;
        height:100%;
        margin:0 auto;
        position:relative;
        font-size:13px;
        .shop{
            padding: 0 10px;
            position:absolute;
            left:800px;
            line-height:36px;
            font-size:16px;
            .fa-shopping-cart{
                margin:3px 0 0 60px;
                cursor: pointer;
                background:url(../static/images/shop.png) no-repeat;
                display:inline-block;
                width:40px;
                height:29px;
                &:hover{
                    color:#df841d;
                    
                }
            }
        }
        .area{
            position: absolute;
            width:200px;
            .detail_area,.switch_city{
                float:left;
                height:36px;
                line-height:36px;
                text-align:center;
                color:#8c8c8c;
                padding:0 10px;
            }
            .border{
                width:1px;
                height:16px;
                margin:10px;
                float:left;
                background-color:rgb(201,201,201);

            }cccc
            .switch_city{
                position:relative;
                &::after{
                    content:"";
                    width:calc(100% + 11px);
                    height:100%;
                    display: block;
                    position: absolute;
                    top:0;
                    left:-11px;
                    border-left:1px solid transparent;
                    border-right:1px solid transparent;
                }
                .switch_icon{
                    height:5px;
                    width:9px;
                    vertical-align: middle;
                    display:inline-block;
                    transition: all 0.3s ease-out;
                    background:url(../images/point.png)  no-repeat;

                }
                &:hover{
                    .switch_icon {
                        transform: rotate(180deg);
                    }
                    &::after{
                    content:"";
                    width:calc(100% + 11px);
                    height:100%;
                    display: block;
                    position: absolute;
                    top:0;
                    left:-11px;
                    border-left:1px solid rgb(201,201,201);
                    border-right:1px solid rgb(201,201,201);
                }
                    

                }
                .hot_city{
                    position:absolute;
                    z-index:999;
                    top:36px;
                    left:-11px;
                    width:240px;
                    border:1px solid rgb(201,201,201);
                    background-color: whitesmoke;
                    text-align: left;
                    line-height:23px;
                    padding-bottom:20px;
                    .hot_city_title{
                        color:rgb(0,117,169);
                        font-weight: bold;
                        margin-left:10px;
                        
                    }
                    .city_item{
                        margin:0 10px;
                        cursor: pointer;
                        &:hover{
                            text-decoration: underline;
                            color:rgb(0,117,169);
                        }
                    }


                
            }
            }
            

        }
        .log_reg{
            position:absolute;
            right:90px;
            font-size:13px;
            .user_img{
                width:30px;
                height:30px;
                border-radius:8px;
                overflow:hidden;
                background-color:red;
                float:left;
                margin-top:4px;
                img{
                    width:100%;
                    height:100%;
                }
            }
            .border{
                width:1px;
                height:20px;
                margin:8px;
                float:left;
                background-color:rgb(201,201,201);
            }
            .logined,.quit,.login,.register{
                color:#8c8c8c;
                height:36px;
                padding:0 10px;
                line-height:36px;
                float:left;
                cursor: pointer;
            
            }
            
            .logined{
                cursor:default;
            }

        }

    }
}
</style>



