import Vue from "vue";
import Vuex from "vuex";
Vue.use(Vuex);

const store = new Vuex.Store({
    strict:true,
    state: {
        // toast 组件默认为不显示
        isShow:false,
        // 商品购买数量
        num:1,
        // 商品详情页子路由的scrollTop
        scrollTop:0,
        // 用户登陆token
        token: null
    },
    mutations: {
        // 切换toast组件的状态
        switchShow (state,isShow){
            state.isShow = isShow;

        },
       
        // 改变商品购买数量
        setGoodsNum (state,num){
            state.num = num;


        },
        // 设置商品详情页子路由的scrollTop
        setScrollTop(state,scrollTop){
            state.scrollTop = scrollTop;

        },
        // 设置用户登陆token
        setToken (state,token){
            state.token = token;

        }
    }



});

export default store;